import React, { useMemo, useState } from "react";
import { motion } from "framer-motion";

const Skills = () => {
  const skillGroups = useMemo(
    () => [
      {
        title: "Languages",
        subtitle: "Core languages I’m building with & learning",
        items: ["C", "Python", "JavaScript", "HTML", "CSS"],
        example: "Main languages for building projects.",
      },
      {
        title: "Tools & Data",
        subtitle: "Frameworks & Documentation",
        items: ["Git", "Docker", "React", "Excel"],
        example: "Version control, containerization, and data analysis.",
      },

      {
        title: "Automation",
        subtitle: "Workflows that save time",
        items: ["n8n", "AI Agents", "JSON", "API", "Workflows", "Scheduling"],
        example: "Turning repetitive tasks into reliable automations to boost productivity.",
      },
      {
        title: "Other Skills",
        subtitle: "Skills to help me grow as an entrepreneur.",
        items: ["Sales", "Lead Generation", "Out-reaching", "Marketing", "Content Creation", "Social Media Management"],
        example: "Cold calling, LinkedIn outreach, and creating content to attract clients.",
      },

    ],
    []
  );

  const focusBullets = [
    "Backend foundations: building APIs and understanding system design basics.",
    "LLM-powered micro-projects (predictors, workflow helpers) to learn by building.",
    "More exposure to data: querying, structuring, and using results effectively.",
  ];

  const [activeIndex, setActiveIndex] = useState(0);

  return (
    <section className="skills-page">
      <motion.h3
        initial={{ y: 20, opacity: 0 }}
        whileInView={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6 }}
        viewport={{ once: true }}
      >
        Skills
      </motion.h3>

      <div className="skills-accordion-layout">
        <div className="skills-accordion">
          {skillGroups.map((group, index) => {
            const isOpen = index === activeIndex;
            const panelId = `skills-panel-${index}`;
            const buttonId = `skills-button-${index}`;

            return (
              <div key={group.title} className="skills-acc-item">
                <button
                  id={buttonId}
                  type="button"
                  className="skills-acc-button"
                  aria-expanded={isOpen}
                  aria-controls={panelId}
                  onClick={() => setActiveIndex(isOpen ? -1 : index)}
                >
                  <span className="skills-acc-index" aria-hidden="true">
                    {String(index + 1).padStart(2, "0")}
                  </span>

                  <span className="skills-acc-text">
                    <span className="skills-acc-title">{group.title}</span>
                    <span className="skills-acc-subtitle">{group.subtitle}</span>
                  </span>

                  <span className={`skills-acc-chevron ${isOpen ? "open" : ""}`} aria-hidden="true">
                    ˅
                  </span>
                </button>

                <motion.div
                  id={panelId}
                  className="skills-acc-panel"
                  role="region"
                  aria-labelledby={buttonId}
                  initial={false}
                  animate={{ height: isOpen ? "auto" : 0, opacity: isOpen ? 1 : 0 }}
                  transition={{ duration: 0.3 }}
                  style={{ overflow: "hidden" }}
                >
                  <div className="skills-acc-panel-inner">
                    <div className="skills-acc-example">{group.example}</div>
                    <div className="skills-chip-wrap">
                      {group.items.map((item) => (
                        <span key={item} className="skills-chip">
                          {item}
                        </span>
                      ))}
                    </div>
                  </div>
                </motion.div>
              </div>
            );
          })}
        </div>

        <motion.aside
          className="skills-aside"
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <h4 className="skills-aside-title">Current focus</h4>
          <p className="skills-aside-subtitle">
            A short roadmap that ties my skills to projects I’m actively building.
          </p>

          <ul className="skills-bullets">
            {focusBullets.map((b) => (
              <li key={b} className="skills-bullet">
                <span className="skills-bullet-dot" aria-hidden="true" />
                {b}
              </li>
            ))}
          </ul>
        </motion.aside>
      </div>
    </section>
  );
};

export default Skills;
